+            ObstacleClass::Static => "STATIC (wall/barrier)",
+            ObstacleClass::Dynamic => "DYNAMIC (movable)",
+            ObstacleClass::Unknown => "UNKNOWN",
+        };
+        println!(
+            "  Obstacle {}: {} (confidence: {:.2})",
+            i, label, c.confidence
