+// Core types
+// ---------------------------------------------------------------------------
+
+/// 3D point used in point clouds and spatial operations.
+#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
+pub struct Point3D {
+    pub x: f32,
+    pub y: f32,
+    pub z: f32,
+}
+
+impl Point3D {
+    pub fn new(x: f32, y: f32, z: f32) -> Self {
+        Self { x, y, z }
+    }
+
+    pub fn distance_to(&self, other: &Point3D) -> f32 {
+        let dx = self.x - other.x;
+        let dy = self.y - other.y;
+        let dz = self.z - other.z;
+        (dx * dx + dy * dy + dz * dz).sqrt()
+    }
+
+    pub fn as_f64_array(&self) -> [f64; 3] {
+        [self.x as f64, self.y as f64, self.z as f64]
+    }
+
+    pub fn from_f64_array(arr: &[f64; 3]) -> Self {
+        Self {
+            x: arr[0] as f32,
+            y: arr[1] as f32,
+            z: arr[2] as f32,
+        }
+    }
+
+    pub fn to_vec(&self) -> Vec<f32> {
+        vec![self.x, self.y, self.z]
+    }
+}
+
+/// A unit quaternion representing a 3-D rotation.
+#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
+pub struct Quaternion {
+    pub x: f64,
+    pub y: f64,
+    pub z: f64,
+    pub w: f64,
+}
+
+impl Default for Quaternion {
+    fn default() -> Self {
+        Self { x: 0.0, y: 0.0, z: 0.0, w: 1.0 }
+    }
+}
+
+impl Quaternion {
+    pub fn identity() -> Self {
+        Self::default()
+    }
+
+    pub fn new(x: f64, y: f64, z: f64, w: f64) -> Self {
+        Self { x, y, z, w }
+    }
+}
+
+/// A 6-DOF pose: position + orientation.
+#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
+pub struct Pose {
+    pub position: [f64; 3],
+    pub orientation: Quaternion,
+    pub frame_id: String,
+}
+
+impl Default for Pose {
+    fn default() -> Self {
+        Self {
+            position: [0.0; 3],
+            orientation: Quaternion::identity(),
+            frame_id: String::new(),
+        }
+    }
+}
+
+/// A collection of 3D points from a sensor (LiDAR, depth camera, etc.).
+#[derive(Debug, Clone, Default, Serialize, Deserialize)]
+pub struct PointCloud {
+    pub points: Vec<Point3D>,
+    pub intensities: Vec<f32>,
+    pub normals: Option<Vec<Point3D>>,
+    pub timestamp_us: i64,
+    pub frame_id: String,
+}
+
+impl PointCloud {
+    pub fn new(points: Vec<Point3D>, timestamp: i64) -> Self {
+        let len = points.len();
+        Self {
+            points,
+            intensities: vec![1.0; len],
+            normals: None,
+            timestamp_us: timestamp,
+            frame_id: String::new(),
+        }
+    }
+
+    pub fn len(&self) -> usize {
+        self.points.len()
+    }
+
+    pub fn is_empty(&self) -> bool {
+        self.points.is_empty()
+    }
+
+    pub fn timestamp(&self) -> i64 {
+        self.timestamp_us
+    }
+}
