+fn pseudo_random_f32(seed: u64, index: usize) -> f32 {
+    let h = seed
+        .wrapping_mul(index as u64 + 1)
+        .wrapping_mul(0x5DEECE66D)
+        .wrapping_add(0xB);
+    ((h % 10000) as f32) / 10000.0
